var e=JSON.parse(`[{"id":"L3_1","type":"dialog","speaker":"GRENADE_TIDE_NULL_NULL","text":{"KOREA":"형님들~ 들으셨습니까?","JPN":"みんな、聞きましたか？","ENG":"Did y'all hear the news?","TWN":"兄弟們~ 聽到了嗎？"},"stage":{"bg":"CITY_STREET_DISASTER_CORRUPT2","slots":{"L":null,"C":{"char_id":"GRENADE_TIDE_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L4_1","type":"dialog","speaker":"GRENADE_TIDE_NULL_NULL","text":{"KOREA":"지금 3종 침식체가 이쪽으로 오고 있다는데요.","JPN":"今、第3種侵食体がこっちに向かっているらしいです。","ENG":"There's a Category 3 headed our way.","TWN":"現在3類侵蝕體正在向這邊移動。"},"stage":{"bg":"CITY_STREET_DISASTER_CORRUPT2","slots":{"L":null,"C":{"char_id":"GRENADE_TIDE_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"SUBMACHINEGUN_TIDE_NULL_NULL","text":{"KOREA":"3종 침식체요......? 그거 엄청 위험한 놈 아닙니까?","JPN":"第3種侵食体ですか……？　あれ、相当危険な奴じゃないですか？","ENG":"Category 3? Isn't that super dangerous?","TWN":"3類侵蝕體……？那不是非常危險的傢伙嗎？"},"stage":{"bg":"CITY_STREET_DISASTER_CORRUPT2","slots":{"L":{"char_id":"GRENADE_TIDE_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SUBMACHINEGUN_TIDE_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L8_1","type":"dialog","speaker":"GRENADE_TIDE_NULL_NULL","text":{"KOREA":"그렇지. 혼자서 도시 하나 박살낼 만큼 인정사정 안 봐 주는 녀석이야.","JPN":"そうだな。単体で都市1つを壊滅できるくらい、容赦のない奴だ。","ENG":"It sure is. Those things are brutal enough to destroy an entire city by themselves.","TWN":"對。單單一個就能將整個城市夷為平地。"},"stage":{"bg":"CITY_STREET_DISASTER_CORRUPT2","slots":{"L":{"char_id":"GRENADE_TIDE_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SUBMACHINEGUN_TIDE_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L9_1","type":"dialog","speaker":"SUBMACHINEGUN_TIDE_NULL_NULL","text":{"KOREA":"그, 그럼 한가하게 떠들 때가 아니잖습니까! 정말 큰일이잖아요!","JPN":"ってことは、今ここでのんびりしている場合ではないじゃないですか！　本当にヤバいんじゃないですか！","ENG":"Th-then we don't have time to lounge around like this! We're in some serious trouble here!","TWN":"那、那該怎麼辦！這情況太糟了！"},"stage":{"bg":"CITY_STREET_DISASTER_CORRUPT2","slots":{"L":{"char_id":"GRENADE_TIDE_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SUBMACHINEGUN_TIDE_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L12_1","type":"dialog","speaker":"SHOTGUN_TIDE_NULL_NULL","text":{"KOREA":"......형님.","JPN":"……兄貴。","ENG":"Sir.","TWN":"……大哥。"},"stage":{"bg":"CITY_STREET_DISASTER_CORRUPT2","slots":{"L":{"char_id":"SHOTGUN_TIDE_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"GUNSHIELD_TIDE_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L13_1","type":"dialog","speaker":"GUNSHIELD_TIDE_NULL_NULL","text":{"KOREA":"나도 들었어.","JPN":"聞こえたぞ。","ENG":"I heard.","TWN":"我也聽到了。"},"stage":{"bg":"CITY_STREET_DISASTER_CORRUPT2","slots":{"L":{"char_id":"SHOTGUN_TIDE_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"GUNSHIELD_TIDE_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L14_1","type":"dialog","speaker":"SHOTGUN_TIDE_NULL_NULL","text":{"KOREA":"어쩌실 겁니까?","JPN":"どうしましょうか？","ENG":"What should we do?","TWN":"你打算怎麼辦？"},"stage":{"bg":"CITY_STREET_DISASTER_CORRUPT2","slots":{"L":{"char_id":"SHOTGUN_TIDE_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"GUNSHIELD_TIDE_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L15_1","type":"dialog","speaker":"SHOTGUN_TIDE_NULL_NULL","text":{"KOREA":"3종 침식체라면 A급 카운터에 준하는 전력이 있어야 붙어 볼 만할 겁니다.","JPN":"第3種侵食体ならAランクカウンターに準ずる戦力がないと手に負えないでしょう。","ENG":"We'll need at least a Grade A Counter to stand a chance against a Category 3.","TWN":"要對付3類侵蝕體，至少需要有與A級制裁者同等戰力才能與之抗衡。"},"stage":{"bg":"CITY_STREET_DISASTER_CORRUPT2","slots":{"L":{"char_id":"SHOTGUN_TIDE_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"GUNSHIELD_TIDE_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L16_1","type":"dialog","speaker":"SHOTGUN_TIDE_NULL_NULL","text":{"KOREA":"녀석 주위에 우글거릴 다른 하급 침식체들까지 생각하면, 저희 전력만으로는......","JPN":"奴らの周辺に大量にいる下級侵食体のことまで考えると、我々の戦力だけでは……","ENG":"Not to mention all those lesser C.O.s swarming about... We simply don't have the firepower.","TWN":"如果再加上其他低階種類的侵蝕體，只靠我們的戰力恐怕……"},"stage":{"bg":"CITY_STREET_DISASTER_CORRUPT2","slots":{"L":{"char_id":"SHOTGUN_TIDE_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"GUNSHIELD_TIDE_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L17_1","type":"dialog","speaker":"GUNSHIELD_TIDE_NULL_NULL","text":{"KOREA":"그렇다고 도망칠 수는 없지.","JPN":"だからって逃げるわけにはいかん。","ENG":"But we can't just flee either.","TWN":"那也不能逃跑吧。"},"stage":{"bg":"CITY_STREET_DISASTER_CORRUPT2","slots":{"L":{"char_id":"SHOTGUN_TIDE_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"GUNSHIELD_TIDE_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L18_1","type":"dialog","speaker":"GUNSHIELD_TIDE_NULL_NULL","text":{"KOREA":"이 뒤는 민간인 거주지역이야. 우리가 내빼면 그곳 시민들은 도망칠 틈도 없이 침식체들에게 당한다.","JPN":"この先は民間人居住地域だ。我々が逃げたら、そこの住民たちは逃げる間もなく侵食体にやられる。","ENG":"There are civilian residences behind us. If we bail, the C.O.s will get to them before they even get a chance to evacuate.","TWN":"我們身後就是居民區。如果我們退縮，這裡的市民們就會受到侵蝕體攻擊，根本沒地方逃跑。"},"stage":{"bg":"CITY_STREET_DISASTER_CORRUPT2","slots":{"L":{"char_id":"SHOTGUN_TIDE_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"GUNSHIELD_TIDE_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L19_1","type":"dialog","speaker":"SHOTGUN_TIDE_NULL_NULL","text":{"KOREA":"......","JPN":"……","ENG":"......","TWN":"……"},"stage":{"bg":"CITY_STREET_DISASTER_CORRUPT2","slots":{"L":{"char_id":"SHOTGUN_TIDE_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"GUNSHIELD_TIDE_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L20_1","type":"dialog","speaker":"GUNSHIELD_TIDE_NULL_NULL","text":{"KOREA":"하지만 이런 데서 목숨을 날릴 멍청이가 많을 필요도 없겠지.","JPN":"だがこんな所で全員死ぬ必要はないだろう。","ENG":"But it doesn't necessarily mean we need to sacrifice the lives of our all troops here.","TWN":"但是也沒必要把整個小隊葬送在這裡。"},"stage":{"bg":"CITY_STREET_DISASTER_CORRUPT2","slots":{"L":{"char_id":"SHOTGUN_TIDE_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"GUNSHIELD_TIDE_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L21_1","type":"dialog","speaker":"GUNSHIELD_TIDE_NULL_NULL","text":{"KOREA":"넌 젊은 녀석들 데리고 후방으로 가라.","JPN":"お前は若い奴らを連れて後方に行け。","ENG":"You take the younger guys and fall back to the rear.","TWN":"你帶著年輕隊員先撤退到後方。"},"stage":{"bg":"CITY_STREET_DISASTER_CORRUPT2","slots":{"L":{"char_id":"SHOTGUN_TIDE_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"GUNSHIELD_TIDE_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L22_1","type":"dialog","speaker":"GUNSHIELD_TIDE_NULL_NULL","text":{"KOREA":"여긴 늙은이들이 버텨 볼 테니까.","JPN":"ここは老いぼれで何とか時間を稼いでみる。","ENG":"We old-timers will try to fend them off here.","TWN":"我們這些老人會幫你們爭取時間。"},"stage":{"bg":"CITY_STREET_DISASTER_CORRUPT2","slots":{"L":{"char_id":"SHOTGUN_TIDE_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"GUNSHIELD_TIDE_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L23_1","type":"dialog","speaker":"SHOTGUN_TIDE_NULL_NULL","text":{"KOREA":"하, 늙어서 치매라도 왔습니까? 닭살 돋는 소리 마십쇼.","JPN":"は？　とうとうボケてきたんですか？　聞いてられませんね。","ENG":"Hah, you going senile in your old age? Surely you don't expect us to go along with that crap.","TWN":"啊，大哥你不是老年癡呆了吧？別說這麼肉麻的話，好不好。"},"stage":{"bg":"CITY_STREET_DISASTER_CORRUPT2","slots":{"L":{"char_id":"SHOTGUN_TIDE_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"GUNSHIELD_TIDE_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L25_1","type":"dialog","speaker":"SHOTGUN_TIDE_NULL_NULL","text":{"KOREA":"우리도 침식체 놈들 앞에서 줄행랑이나 치려고 이 빌어먹을 강화복 걸친 게 아닙니다.","JPN":"私たちだって侵食体を前にして逃げるために、こんなクソ重い強化服を纏ったんじゃないです。","ENG":"We're not wearing these freaking power suits just so we can turn tail and run from C.O.s.","TWN":"我們穿上這身強化服，可不是為了看到侵蝕體就夾起尾巴逃跑。"},"stage":{"bg":"CITY_STREET_DISASTER_CORRUPT2","slots":{"L":null,"C":{"char_id":"SHOTGUN_TIDE_NULL_NULL","face":"UNIT_IDLE"},"R":null}}}]`);export{e as default};